/**
 * Service de mise en cache pour améliorer les performances du frontend
 */

// Durée par défaut du cache en minutes
const DEFAULT_CACHE_DURATION = 5;

// Obtenir la durée en millisecondes
const getCacheDuration = (minutes = DEFAULT_CACHE_DURATION) => {
  return minutes * 60 * 1000;
};

// Stocker une valeur dans le cache
export const setCacheItem = (key, value, expirationMinutes = DEFAULT_CACHE_DURATION) => {
  const item = {
    value,
    expiry: new Date().getTime() + getCacheDuration(expirationMinutes)
  };
  localStorage.setItem(`cache_${key}`, JSON.stringify(item));
  console.log(`Mise en cache: ${key}`);
};

// Récupérer une valeur du cache
export const getCacheItem = (key) => {
  const cachedItem = localStorage.getItem(`cache_${key}`);

  if (!cachedItem) {
    return null;
  }

  const item = JSON.parse(cachedItem);
  const now = new Date().getTime();

  // Vérifier si l'élément a expiré
  if (now > item.expiry) {
    localStorage.removeItem(`cache_${key}`);
    console.log(`Cache expiré: ${key}`);
    return null;
  }

  console.log(`Récupéré du cache: ${key}`);
  return item.value;
};

// Supprimer une valeur du cache
export const removeCacheItem = (key) => {
  localStorage.removeItem(`cache_${key}`);
};

// Vider tout le cache
export const clearCache = () => {
  Object.keys(localStorage)
    .filter(key => key.startsWith('cache_'))
    .forEach(key => localStorage.removeItem(key));
};

// Fonction utilitaire pour les requêtes API avec mise en cache
export const fetchWithCache = async (url, options = {}, cacheMinutes = DEFAULT_CACHE_DURATION) => {
  // Ne pas utiliser le cache pour les requêtes non-GET
  if (options.method && options.method !== 'GET') {
    return fetch(url, options);
  }

  const cacheKey = `${url}_${JSON.stringify(options)}`;
  const cachedData = getCacheItem(cacheKey);

  if (cachedData) {
    return Promise.resolve(new Response(new Blob([JSON.stringify(cachedData)], 
      { type: 'application/json' })));
  }

  const response = await fetch(url, options);
  const data = await response.clone().json();

  if (response.ok) {
    setCacheItem(cacheKey, data, cacheMinutes);
  }

  return response;
};
